function isOriginAllowed(origin, allowedOrigin) {
  if (Array.isArray(allowedOrigin)) {
    for (var i = 0; i < allowedOrigin.length; ++i) {
      if (isOriginAllowed(origin, allowedOrigin[i])) {
        return true;
      }
    }
    return false;
  } else if (isString(allowedOrigin)) {
    return origin === allowedOrigin;
  } else if (allowedOrigin instanceof RegExp) {
    return allowedOrigin.test(origin);
  } else {
    return !!allowedOrigin;
  }
}

function applyHeaders(headers, res) {
  for (var i = 0, n = headers.length; i < n; i++) {
    var header = headers[i];
    if (header) {
      if (Array.isArray(header)) {
        applyHeaders(header, res);
      } else if (header.key === 'Vary' && header.value) {
        vary(res, header.value);
      } else if (header.value) {
        res.setHeader(header.key, header.value);
      }
    }
  }
}

isArray(options: { min?: number; max?: number } = {}) {
  return this.custom(
    value =>
      Array.isArray(value) &&
      (typeof options.min === 'undefined' || value.length >= options.min) &&
      (typeof options.max === 'undefined' || value.length <= options.max),
  );
}

mapped(): Record<string, T> {
  return this.errors.reduce((mapping, error) => {
    const key = error.type === 'field' ? error.path : `_${error.type}`;
    if (!mapping[key]) {
      mapping[key] = this.formatter(error);
    }

    return mapping;
  }, {} as Record<string, T>);
}

const DEFAULT_MAX_AGE = 365 * 24 * 60 * 60;

function parseMaxAge(value: number = DEFAULT_MAX_AGE): number {
  if (value >= 0 && Number.isFinite(value)) {
    return Math.floor(value);
  } else {
    throw new Error(
      `Strict-Transport-Security: ${JSON.stringify(
        value,
      )} is not a valid value for maxAge. Please choose a positive integer.`,
    );
  }
}

var serveFiles = function (swaggerDoc, opts) {
  opts = opts || {}
  var initOptions = {
    swaggerDoc: swaggerDoc || undefined,
    customOptions: opts.swaggerOptions || {},
    swaggerUrl: opts.swaggerUrl || {},
    swaggerUrls: opts.swaggerUrls || undefined
  }
  var swaggerInitWithOpts = swaggerInitFunction(swaggerDoc, initOptions)
  return [swaggerInitWithOpts, swaggerAssetMiddleware()]
}

get user() {
  try {
    const {
      config: { identityClaimFilter },
    } = weakRef(this);
    const { idTokenClaims } = this;
    const user = clone(idTokenClaims);
    identityClaimFilter.forEach((claim) => {
      delete user[claim];
    });
    return user;
  } catch {
    return undefined;
  }
}

export const setRetryAfterHeader = (
	response: Response,
	info: RateLimitInfo,
	windowMs: number,
): void => {
	if (response.headersSent) return

	const resetSeconds = getResetSeconds(windowMs, info.resetTime)
	response.setHeader('Retry-After', resetSeconds.toString())
}

